import{_ as a,o,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"84A. Change Of Ward Allowance","description":"","frontmatter":{"title":"84A. Change Of Ward Allowance","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","allowances"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/84A-change-of-ward-allowance.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/84A-change-of-ward-allowance.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/allowances/84A-change-of-ward-allowance.md"};function s(l,e,i,h,p,d){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_84a-change-of-ward-allowance" tabindex="-1">84A. Change Of Ward Allowance <a class="header-anchor" href="#_84a-change-of-ward-allowance" aria-label="Permalink to &quot;84A. Change Of Ward Allowance&quot;">​</a></h1><p><strong>84A.1</strong> Definitions</p><p>In this clause:</p><p><strong>(a)</strong> Base Ward means the Ward or Unit to which the Employee was rostered to work in accordance with <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.html">clause 94</a> (Rosters).</p><p><strong>(b)</strong> Multi Base Ward Employee means an Employee who is contracted to work on more than one Base Ward.</p><p><strong>84A.2</strong> Relocation from Base Ward –</p><p><strong>(a)</strong> The Employer will ensure that rosters are issued on a per ward or unit basis.</p><p><strong>(b)</strong> The allowance under this clause shall apply from FFPPOA 20 May 2025.</p><p><strong>(c)</strong> Where, at the initiative of the Employer, an Employee performs their rostered shift at a ward, unit or Department that is not their Base Ward, the Employee will be entitled to the Change of Ward Allowance.</p><p><strong>(d)</strong> The Change of Ward Allowance is set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>84A.3</strong> Change of Ward Allowance - exceptions The allowance in this clause does not apply to:</p><p><strong>(a)</strong> A casual Employee, including a Bank Employee</p><p><strong>(b)</strong> A Pool Employee</p><p><strong>(c)</strong> An Employee whose role is genuinely not ward/unit based, such as an After-Hours Coordinator, Educators, Advanced Practice Nurse or who does not ordinarily work in a ward</p><p><strong>(d)</strong> An Employee not rostered to work in an aged care ward, undertaking ad hoc assessment or supervision duties in an aged care ward for part of a shift</p><p><strong>(e)</strong> An additional shift that a part-time Employee has agreed to work, unless relocated from the ward on which the additional shift was scheduled to take place</p><p><strong>(f)</strong> A post-registration student who is required to operate in another ward, unit or department due to their academic requirements.</p><p><strong>(g)</strong> A Nurse who is required to follow their patient to other units/wards e.g. ECT; or</p><p><strong>(h)</strong> Working from home arrangements or other like arrangements; or</p><p><strong>(i)</strong> A Multi Base Ward Employee to the extent they are working on a Base Ward in accordance with their roster.</p><p>Example: An Employee is contracted to work on Ward A on some days, and Ward B on other days. Ward A and Ward B are Base Wards for the purposes of this clause. A Multi Base Ward Employee who, at the initiative of the Employer, performs their rostered shift at a ward, unit or department that is not their Base Ward, will be entitled to the Change of Ward Allowance.</p><p><strong>84A.4</strong> Anti-avoidance Employers must not seek to circumvent this provision by, for example, defining multiple wards as one ward, declaring Employees to be part of a pool arrangement or Multi Base Ward Employee contrary to their wishes, amalgamating cost centres, or not rostering to a ward, unit, clinical section or department where that would ordinarily be the case.</p><p><strong>84A.5</strong> Additional Provisions Additional provisions apply where an Employee redeploys to a Campus that is not their Base Employment Campus (See <a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/82-travelling-and-relocation-allowance.html">clause 82</a> Traveling and Relocation Allowance), or the redeployment is as a result of the Employee being an Affected Employee (see clause 20.2(a)).</p>',23)])])}const g=a(n,[["render",s]]);export{m as __pageData,g as default};
